CREATE OR REPLACE FUNCTION fpb_get_share_amount (as_member_no text) RETURNS bigint AS $body$
DECLARE

  ldc_share_period_amount bigint;

BEGIN
  select sc_mem_m_share_mem.share_amount into STRICT ldc_share_period_amount  from sc_mem_m_share_mem where trim(both membership_no) = trim(both as_member_no);

